// Instead of one massive component with many props:
// <Card title="..." subtitle="..." image="..." actions={} footer={} ... />

// Build composable parts:
function Card({ children }: { children: React.ReactNode }) {
  return <div className="card">{children}</div>;
}

function CardHeader({ children }: { children: React.ReactNode }) {
  return <div className="card__header">{children}</div>;
}

function CardBody({ children }: { children: React.ReactNode }) {
  return <div className="card__body">{children}</div>;
}

function CardFooter({ children }: { children: React.ReactNode }) {
  return <div className="card__footer">{children}</div>;
}

// Compose them however you need:
function ProductCard({ product }: { product: Product }) {
  return (
    <Card>
      <CardHeader>
        <h3>{product.name}</h3>
        <span>${product.price}</span>
      </CardHeader>
      <CardBody>
        <p>{product.description}</p>
      </CardBody>
      <CardFooter>
        <button>Add to Cart</button>
      </CardFooter>
    </Card>
  );
}

// Or a simpler variant:
function AlertCard({ message }: { message: string }) {
  return (
    <Card>
      <CardBody>
        <p>{message}</p>
      </CardBody>
    </Card>
  );
}
